static int timespec_is_valid(const struct timespec *ts) {
  return ts->tv_sec >= 0 && ts->tv_nsec < 1000000000ULL;
}

static uint64 timespec_to_ticks_ceil(const struct timespec *ts) {
  const uint64 tick_ns = 1000000000ULL / TICKS_PER_SECOND;
  uint64 ns = (uint64)ts->tv_sec * 1000000000ULL + ts->tv_nsec;
  if(ns == 0) {
    return 0;
  }
  return (ns + tick_ns - 1) / tick_ns;
}

static void ticks_to_timespec64(uint64 rticks, struct timespec *ts) {
  ts->tv_sec = rticks / TICKS_PER_SECOND;
  ts->tv_nsec = (rticks % TICKS_PER_SECOND) * (1000000000ULL / TICKS_PER_SECOND);
}

/**
 * @brief clock_nanosleep() allows the calling thread to
       sleep for an interval specified with nanosecond precision.  It
       differs in allowing the caller to select the clock against which
       the sleep interval is to be measured, and in allowing the sleep
       interval to be specified as either an absolute or a relative
       value.
 * @property int clock_nanosleep(clockid_t clock_id,
                            int flags,
                            const struct timespec *request,
                            struct timespec *_Nullable remain);

 * @return   On successfully sleeping for the requested interval,
       clock_nanosleep() returns 0.  If the call is interrupted by a
       signal handler or encounters an error, then it returns one of the
       positive error number listed in ERRORS. 
 */
uint64 sys_clock_nanosleep(void) {
  int clock_id, flags;
  uint64 addr0, addr1;
  struct timespec req, rem;
  uint64 rticks = 0;
  uint ticks0;
  struct proc *p = myproc();
  argint(0, &clock_id);
  argint(1, &flags);
  argaddr(2, &addr0);
  argaddr(3, &addr1);

  if (copyin(myproc()->mm.pagetable, (char *)&req, addr0, sizeof(struct timespec)) < 0)
    return -EFAULT;
  if((clock_id != CLOCK_REALTIME && clock_id != CLOCK_MONOTONIC) ||
     (flags & ~TIMER_ABSTIME) || !timespec_is_valid(&req)) {
    return -EINVAL;
  }
  acquire(&tickslock);
  ticks0 = ticks;

#ifdef __DEBUG_SYS_CLOCK_NANOSLEEP
  Log("[sys_clock_nanosleep] clock_id: %d, flags: %d, addr0: %p, addr1: %p", clock_id, flags, (void *)addr0, (void *)addr1);
  Log("req_sec: %d, req_nsec %d, rticks: %d", req.tv_sec, req.tv_nsec, rticks);
#endif
  if(flags & TIMER_ABSTIME) {
    uint64 target_ticks = timespec_to_ticks_ceil(&req);
    if(target_ticks <= ticks0) {
      release(&tickslock);
      return 0;
    }
    rticks = target_ticks - ticks0;
  } else {
    rticks = timespec_to_ticks_ceil(&req);
  }
  while (ticks - ticks0 < rticks)
  {
      if (proc_killed(p))
      {   
          if(addr1) {
            uint64 elapsed = ticks - ticks0;
            uint64 remaining = elapsed < rticks ? rticks - elapsed : 0;
            ticks_to_timespec64(remaining, &rem);
            copyout(p->mm.pagetable, addr1, (char *)&rem, sizeof(rem));
          }
          release(&tickslock);
          return -EINTR;
      }

